-- TOC entry 271 (class 1255 OID 155687)
-- Name: get_products_for_car(uuid, text, text); Type: FUNCTION; Schema: sales; Owner: neondb_owner
--

CREATE FUNCTION sales.get_products_for_car(car_id uuid DEFAULT NULL::uuid, car_type text DEFAULT NULL::text, car_size text DEFAULT NULL::text) RETURNS TABLE(mp_id uuid, mp_name text, mp_category text, mp_brand text, mp_price numeric, mp_description text, mp_image text, compatibility_score integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        p.mp_id,
        p.mp_name,
        p.mp_category,
        p.mp_brand,
        p.mp_price,
        p.mp_description,
        p.mp_image,
        CASE
            -- Perfect match: product explicitly compatible with this car's type and size
            WHEN p.mp_compatible_car_types IS NOT NULL 
                 AND p.mp_recommended_car_sizes IS NOT NULL
                 AND (car_type = ANY(p.mp_compatible_car_types) OR car_type IS NULL)
                 AND (car_size = ANY(p.mp_recommended_car_sizes) OR car_size IS NULL)
            THEN 100
            
            -- Good match: compatible with car type
            WHEN p.mp_compatible_car_types IS NOT NULL 
                 AND (car_type = ANY(p.mp_compatible_car_types) OR car_type IS NULL)
            THEN 80
            
            -- Decent match: compatible with car size
            WHEN p.mp_recommended_car_sizes IS NOT NULL 
                 AND (car_size = ANY(p.mp_recommended_car_sizes) OR car_size IS NULL)
            THEN 70
            
            -- Universal product (no restrictions)
            WHEN p.mp_compatible_car_types IS NULL 
                 AND p.mp_recommended_car_sizes IS NULL
            THEN 60
            
            -- Not ideal but still available
            ELSE 50
        END AS compatibility_score
    FROM sales.master_products p
    WHERE p.mp_is_active = TRUE
    ORDER BY 
        compatibility_score DESC,
        p.mp_category,
        p.mp_price DESC;
END;
$$;


ALTER FUNCTION sales.get_products_for_car(car_id uuid, car_type text, car_size text) OWNER TO neondb_owner;

