-- Name: master_customer_problems; Type: TABLE; Schema: sales; Owner: neondb_owner
--

CREATE TABLE sales.master_customer_problems (
    mcp_id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    mcp_problem_title text NOT NULL,
    mcp_keywords text[],
    mcp_description text,
    mcp_embedding public.vector(1024),
    mcp_is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    mcp_recommended_approach text,
    mcp_search_vector tsvector GENERATED ALWAYS AS (to_tsvector('indonesian'::regconfig, ((COALESCE(mcp_problem_title, ''::text) || ' '::text) || COALESCE(mcp_description, ''::text)))) STORED
);


ALTER TABLE sales.master_customer_problems OWNER TO neondb_owner;

--
-- TOC entry 220 (class 1259 OID 24916)
-- Name: master_products; Type: TABLE; Schema: sales; Owner: neondb_owner
--

CREATE TABLE sales.master_products (
    mp_id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    mp_name text NOT NULL,
    mp_category text NOT NULL,
    mp_brand text,
    mp_price numeric(12,2),
    mp_description text,
    mp_features text[],
    mp_power_spec text,
    mp_is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    mp_image text,
    mp_solves_problem_id uuid,
    mp_embedding public.vector(1024),
    mp_compatible_car_types text[],
    mp_recommended_car_sizes text[],
    mp_search_vector tsvector GENERATED ALWAYS AS (to_tsvector('indonesian'::regconfig, ((((((COALESCE(mp_name, ''::text) || ' '::text) || COALESCE(mp_description, ''::text)) || ' '::text) || COALESCE(mp_brand, ''::text)) || ' '::text) || COALESCE(mp_category, ''::text)))) STORED
);


ALTER TABLE sales.master_products OWNER TO neondb_owner;

--
-- TOC entry 3676 (class 0 OID 0)
-- Dependencies: 220
-- Name: COLUMN master_products.mp_compatible_car_types; Type: COMMENT; Schema: sales; Owner: neondb_owner
--

COMMENT ON COLUMN sales.master_products.mp_compatible_car_types IS 'Array of car types this product is suitable for (MPV, SUV, City Car, Sedan, etc). NULL = universal compatibility';


--
-- TOC entry 3677 (class 0 OID 0)
-- Dependencies: 220
-- Name: COLUMN master_products.mp_recommended_car_sizes; Type: COMMENT; Schema: sales; Owner: neondb_owner
--

COMMENT ON COLUMN sales.master_products.mp_recommended_car_sizes IS 'Array of cabin sizes this product works best for (small, medium, large). NULL = suitable for all sizes';


--
-- TOC entry 223 (class 1259 OID 164021)
-- Name: v_hybrid_search_comparison; Type: VIEW; Schema: sales; Owner: neondb_owner
--

CREATE VIEW sales.v_hybrid_search_comparison AS
 SELECT mcp_id,
    mcp_problem_title,
    mcp_description,
    (mcp_embedding IS NOT NULL) AS has_vector,
    (to_tsvector('indonesian'::regconfig, ((COALESCE(mcp_problem_title, ''::text) || ' '::text) || COALESCE(mcp_description, ''::text))) IS NOT NULL) AS has_fts,
    length(COALESCE(mcp_description, ''::text)) AS desc_length,
    array_length(COALESCE(mcp_keywords, ARRAY[]::text[]), 1) AS keyword_count
   FROM sales.master_customer_problems p
  WHERE (mcp_is_active = true);


ALTER VIEW sales.v_hybrid_search_comparison OWNER TO neondb_owner;

--
-- TOC entry 3678 (class 0 OID 0)
-- Dependencies: 223
-- Name: VIEW v_hybrid_search_comparison; Type: COMMENT; Schema: sales; Owner: neondb_owner
--

COMMENT ON VIEW sales.v_hybrid_search_comparison IS 'Diagnostic view showing which problems have vector embeddings and FTS indexes';


